// src/components/LocalFileBrowser/index.jsx
import React, { useState, useEffect, useCallback } from 'react';
import { Breadcrumb, Input, List, Button, message } from 'antd';
import axios from 'axios';
import { FolderOutlined, FileImageOutlined } from '@ant-design/icons';
import { useHistory } from 'react-router-dom'; // if you need to redirect or navigate

const LocalFileBrowser = ({ basePath, setImages }) => {
  const [currentPath, setCurrentPath] = useState(basePath || '');
  const [folders, setFolders] = useState([]);
  const [folderContents, setFolderContents] = useState({ directories: [], files: [] });

  const history = useHistory();

  // A function to fetch directory contents
  const fetchDirectoryContents = useCallback(async (path) => {
    try {
      const response = await axios.get(`/file_browser/browse/${encodeURIComponent(path)}`);
      setFolderContents(response.data);
    } catch (error) {
      message.error('Error fetching directory contents');
      console.error("Error fetching directory contents:", error);
    }
  }, []);

  // Calling fetchDirectoryContents when the component mounts
  // and when currentPath changes
  useEffect(() => {
    fetchDirectoryContents(currentPath);
  }, [currentPath, fetchDirectoryContents]);

  // Handler for Breadcrumb navigation
  const handleBreadcrumbClick = (path) => {
    setCurrentPath(path);
  };

  // Handler for File/Folder click
  const handleItemClick = (item) => {
    if (item.isDirectory) {
      setCurrentPath(item.path);
    } else if (item.isFile) {
      // Update the ImageGrid here or via context
      setImages(prev => [...prev, item.path]);
    }
  };

  return (
    <>
      <Input.Search
        placeholder="Enter a directory path"
        enterButton="Go"
        defaultValue={basePath}
        onSearch={value => setCurrentPath(value)}
      />
      <Breadcrumb>
        {/* Generate Breadcrumb items based on the currentPath */}
        <Breadcrumb.Item onClick={() => handleBreadcrumbClick(basePath)}>
          Home (Start at the basePath)
        </Breadcrumb.Item>
        {currentPath.split('/').map((dir, index, array) => {
          const path = array.slice(0, index + 1).join('/');
          return (
            <Breadcrumb.Item
              key={path}
              onClick={() => handleBreadcrumbClick(path)}
            >
              {dir}
            </Breadcrumb.Item>
          );
        })}
      </Breadcrumb>
      <List
        bordered
        dataSource={folderContents.directories}
        renderItem={dir => (
          <List.Item key={dir} onClick={() => handleItemClick({ path: dir, isDirectory: true })}>
            <FolderOutlined /> {dir}
          </List.Item>
        )}
      />
      <List
        bordered
        dataSource={folderContents.files}
        renderItem={file => (
          <List.Item key={file} onClick={() => handleItemClick({ path: file, isFile: true })}>
            <FileImageOutlined /> {file}
          </List.Item>
        )}
      />
      {/* Include other UI elements for pagination if necessary */}
    </>
  );
};

export default LocalFileBrowser;
```

In this example:

- `basePath` is the starting point (root directory) from where to display the folder contents.
- `setImages` is a callback function to update the list of images, which can be managed in the parent component's state and passed down to the ImageGrid.
- Breadcrumbs are generated based on `currentPath` string split by directory separator (`/`).
- The `fetchDirectoryContents` method is called when the `currentPath` changes to update the folder contents shown in the lists.
- Clicking a breadcrumb changes the current path to that directory, and the folder contents are updated with a new API call.
- Clicking on a folder updates the current path to navigate into the folder.

