// Inside your ImageGrid component...

const lastSelectedIndex = useRef(null); // Helper ref to keep track of last selected item

const handleSelectImage = (image, index, event) => {
  if (event.shiftKey && lastSelectedIndex.current !== null) {
    // Handle shift-click range selection
    const start = Math.min(lastSelectedIndex.current, index);
    const end = Math.max(lastSelectedIndex.current, index) + 1;
    setSelectedImages(prevSelected => (
      [...new Set([...prevSelected, ...images.slice(start, end)])]
    ));
  } else if (event.ctrlKey || event.metaKey) {
    // Handle ctrl/cmd-click to toggle an individual selection
    setSelectedImages(prevSelected => (
      prevSelected.includes(image)
        ? prevSelected.filter(i => i !== image)
        : [...prevSelected, image]
    ));
  } else {
    // Regular click sets the selection to just this item
    setSelectedImages([image]);
  }
  lastSelectedIndex.current = index;
};
